package server

// Provider availability and utilization endpoints — FEAT-002 §26-27.
// Field semantics, unknown-state rules, and the zero-fabrication contract are
// governed by FEAT-014 (dashboard read model).

import (
	"context"
	"encoding/json"
	"net/http"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// ---- Read-model types ----

// ProviderSummary is the list-response item for GET /api/providers.
// -1 sentinels on numeric fields mean unknown (FEAT-014 zero-fabrication).
type ProviderSummary struct {
	Harness            string   `json:"harness"`
	DisplayName        string   `json:"display_name"`
	Status             string   `json:"status"`         // available | unavailable | unknown
	AuthState          string   `json:"auth_state"`     // authenticated | unauthenticated | unknown
	QuotaHeadroom      string   `json:"quota_headroom"` // ok | blocked | unknown
	SignalSources      []string `json:"signal_sources"`
	FreshnessTS        string   `json:"freshness_ts,omitempty"`
	LastCheckedTS      string   `json:"last_checked_ts,omitempty"`
	RecentSuccessRate  float64  `json:"recent_success_rate"`   // -1 when sample_count < 3
	RecentLatencyP50MS int      `json:"recent_latency_p50_ms"` // -1 when unknown
	CostClass          string   `json:"cost_class"`
}

// ProviderModelQuota is per-model quota info within a provider detail.
type ProviderModelQuota struct {
	Model         string `json:"model"`
	QuotaHeadroom string `json:"quota_headroom"` // ok | blocked | unknown
	Source        string `json:"source"`
	SourceNote    string `json:"source_note,omitempty"`
}

// ProviderUsageWindow holds token/cost totals for one time window.
// -1 sentinel means unknown per FEAT-014 zero-fabrication contract.
type ProviderUsageWindow struct {
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	CostNote     string  `json:"cost_note,omitempty"`
}

// ProviderHistoricalUsage holds 7d and 30d usage windows.
type ProviderHistoricalUsage struct {
	Window7D  *ProviderUsageWindow `json:"window_7d,omitempty"`
	Window30D *ProviderUsageWindow `json:"window_30d,omitempty"`
}

// ProviderBurnEstimate is the DDx-derived subscription-pressure estimate.
type ProviderBurnEstimate struct {
	DailyTokenRate   float64 `json:"daily_token_rate"`  // -1 when unknown
	SubscriptionBurn string  `json:"subscription_burn"` // low | moderate | high | unknown
	Source           string  `json:"source,omitempty"`
	Confidence       string  `json:"confidence"` // high | medium | low
	FreshnessTS      string  `json:"freshness_ts,omitempty"`
}

// ProviderPerformance holds DDx-observed latency/success metrics.
type ProviderPerformance struct {
	P50LatencyMS int     `json:"p50_latency_ms"` // -1 when unknown
	P95LatencyMS int     `json:"p95_latency_ms"` // -1 when unknown
	SuccessRate  float64 `json:"success_rate"`   // -1 when sample_count < 3
	SampleCount  int     `json:"sample_count"`
	Window       string  `json:"window"` // "7d"
}

// ProviderRoutingSignals is the routing signal summary within a provider detail.
type ProviderRoutingSignals struct {
	Availability string              `json:"availability"` // available | unavailable | unknown
	RequestFit   string              `json:"request_fit"`  // capable | unknown
	CostEstimate string              `json:"cost_estimate"`
	Performance  ProviderPerformance `json:"performance"`
}

// ProviderDetail is the response shape for GET /api/providers/{harness}.
type ProviderDetail struct {
	Harness         string                   `json:"harness"`
	DisplayName     string                   `json:"display_name"`
	Status          string                   `json:"status"`
	AuthState       string                   `json:"auth_state"`
	Models          []ProviderModelQuota     `json:"models"`
	HistoricalUsage *ProviderHistoricalUsage `json:"historical_usage,omitempty"`
	BurnEstimate    *ProviderBurnEstimate    `json:"burn_estimate,omitempty"`
	RoutingSignals  ProviderRoutingSignals   `json:"routing_signals"`
	SignalSources   []string                 `json:"signal_sources"`
	FreshnessTS     string                   `json:"freshness_ts,omitempty"`
}

// ---- HTTP handlers ----

// handleListProviders serves GET /api/providers — list all configured harnesses
// with routing availability, auth state, quota/headroom, and signal freshness.
// Not project-scoped; provider config is host+user global.
func (s *Server) handleListProviders(w http.ResponseWriter, r *http.Request) {
	now := time.Now().UTC()
	infos, err := listHarnessInfos(r.Context(), s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	report := liveRouteStatusReport(r.Context(), s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		signal := signalFromHarnessInfo(info, now)
		result = append(result, buildProviderSummary(info, signal, report, now))
	}
	writeJSON(w, http.StatusOK, result)
}

// handleShowProvider serves GET /api/providers/{harness} — full routing signal
// snapshot per FEAT-014 read-model fields.
func (s *Server) handleShowProvider(w http.ResponseWriter, r *http.Request) {
	harnessName := r.PathValue("harness")
	if harnessName == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "harness required"})
		return
	}
	infos, err := listHarnessInfos(r.Context(), s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "harness not found"})
		return
	}

	now := time.Now().UTC()
	signal := signalFromHarnessInfo(info, now)
	report := liveRouteStatusReport(r.Context(), s.WorkingDir)

	detail := buildProviderDetail(info, signal, report, now)
	writeJSON(w, http.StatusOK, detail)
}

// ---- MCP tool implementations ----

func (s *Server) mcpProviderList() mcpToolResult {
	now := time.Now().UTC()
	infos, err := listHarnessInfos(context.Background(), s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}

	report := liveRouteStatusReport(context.Background(), s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		signal := signalFromHarnessInfo(info, now)
		result = append(result, buildProviderSummary(info, signal, report, now))
	}
	data, err := json.Marshal(result)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("[]")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

func (s *Server) mcpProviderShow(harnessName string) mcpToolResult {
	if harnessName == "" {
		return mcpToolResult{Content: []mcpContent{mcpText("harness required")}, IsError: true}
	}
	infos, err := listHarnessInfos(context.Background(), s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		return mcpToolResult{Content: []mcpContent{mcpText("harness not found: " + harnessName)}, IsError: true}
	}

	now := time.Now().UTC()
	signal := signalFromHarnessInfo(info, now)
	report := liveRouteStatusReport(context.Background(), s.WorkingDir)

	detail := buildProviderDetail(info, signal, report, now)
	data, err := json.Marshal(detail)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("{}")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

// ---- Build helpers ----

// signalFromHarnessInfo translates upstream HarnessInfo into the
// ddx-local RoutingSignalSnapshot shape used by buildProviderSummary /
// buildProviderDetail. This is the vocabulary translation shim introduced
// when the DDx-side provider-native parsers were retired (ddx-7bc0c8d5):
// upstream quota.Status values "ok|stale|unavailable" map to the existing
// "fresh|stale|unknown" vocabulary that the GraphQL/REST surface exposes so
// the SvelteKit frontend renders identically.
func signalFromHarnessInfo(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
	snap := agent.RoutingSignalSnapshot{Provider: info.Name}

	if info.Account != nil && (info.Account.Email != "" || info.Account.PlanType != "" || info.Account.OrgName != "") {
		snap.Account = &agent.AccountInfo{
			Email:    info.Account.Email,
			PlanType: info.Account.PlanType,
			OrgName:  info.Account.OrgName,
		}
	}

	if info.Quota == nil {
		snap.CurrentQuota = agent.QuotaSignal{
			Source: agent.SignalSourceMetadata{
				Provider:  info.Name,
				Kind:      "docs-only",
				Freshness: "unknown",
			},
			State: "unknown",
		}
		snap.Source = snap.CurrentQuota.Source
		return snap
	}

	// Translate upstream quota.Status (ok|stale|unavailable|unauthenticated|unknown)
	// into the existing ddx vocabulary.
	state := "unknown"
	switch info.Quota.Status {
	case "ok":
		state = "ok"
	case "stale":
		state = "ok" // stale-but-present data still counts as headroom.
	case "unavailable", "unauthenticated":
		state = "unknown"
	}

	// Promote worst non-extra window to "blocked" if any window is blocked.
	var usedPercent int
	var windowMinutes int
	var resetsAt string
	var translatedWindows []agent.QuotaWindow
	for _, w := range info.Quota.Windows {
		qw := agent.QuotaWindow{
			Name:          w.Name,
			LimitID:       w.LimitID,
			WindowMinutes: w.WindowMinutes,
			UsedPercent:   w.UsedPercent,
			ResetsAt:      w.ResetsAt,
			ResetsAtUnix:  w.ResetsAtUnix,
			State:         w.State,
		}
		translatedWindows = append(translatedWindows, qw)
		if w.LimitID == "extra" {
			continue
		}

		return 0
	}
	// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
	// buckets; 1h buckets gives 24.
	n := 24
	if n > len(buckets) {
		n = len(buckets)
	}
	tail := buckets[len(buckets)-n:]
	tokens := make([]float64, len(tail))
	for i, b := range tail {
		tokens[i] = float64(b.Tokens)
	}
	perBucket := agent.LinearSlope(tokens)
	// Convert slope-per-bucket to slope-per-hour.
	var bucketHours float64
	if len(tail) >= 2 {
		bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
	}
	if bucketHours <= 0 {
		bucketHours = 1
	}
	perHour := perBucket / bucketHours
	if perHour <= 0 {
		return 0
	}
	if remaining <= 0 {
		return 0
	}
	hours := remaining / perHour
	if hours <= 0 {
		return 0
	}
	return hours
}

func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
	if maxBuckets <= 0 || len(buckets) == 0 {
		return 0
	}
	if maxBuckets > len(buckets) {
		maxBuckets = len(buckets)
	}
	total := 0
	for _, b := range buckets[len(buckets)-maxBuckets:] {
		total += b.Tokens
	}
	return total
}

func liveProviderInfos(ctx context.Context, workDir string) ([]agentlib.ProviderInfo, error) {
	svc, err := agent.NewStatusProbeServiceFromWorkDir(workDir)
	if err != nil {
		return nil, err
	}
	return svc.ListProviders(ctx)
}

func refreshProviderStatuses(workDir string) {
	providerStatusCache.Lock()
	if providerStatusCache.inFlight[workDir] {
		providerStatusCache.Unlock()
		return
	}
	providerStatusCache.inFlight[workDir] = true
	providerStatusCache.Unlock()

	go func() {
		defer func() {
			providerStatusCache.Lock()
			delete(providerStatusCache.inFlight, workDir)
			providerStatusCache.Unlock()
		}()
		ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
		defer cancel()
		providers, err := liveProviderInfos(ctx, workDir)
		if err != nil {
			return
		}
		rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
		storeProviderRows(workDir, rows)
	}()
}

func cachedProviderRows(workDir string) []*ProviderStatus {
	providerStatusCache.Lock()
	defer providerStatusCache.Unlock()
	return cloneProviderRows(providerStatusCache.rows[workDir])
}

func storeProviderRows(workDir string, rows []*ProviderStatus) {
	providerStatusCache.Lock()
	defer providerStatusCache.Unlock()
	providerStatusCache.rows[workDir] = cloneProviderRows(rows)
}

func providerStatusesFromInfos(providers []agentlib.ProviderInfo, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
	lastChecked := now.UTC().Format(time.RFC3339)
	results := make([]*ProviderStatus, 0, len(providers))
	for _, p := range providers {
		url := p.BaseURL
		if url == "" {
			url = "(api)"
		}
		ps := &ProviderStatus{
			Name:              p.Name,
			Kind:              ProviderKindEndpoint,
			ProviderType:      p.Type,
			BaseURL:           url,
			Model:             p.DefaultModel,
			Status:            p.Status,
			Reachable:         providerReachable(p),
			Detail:            providerDetail(p),
			ModelCount:        p.ModelCount,
			IsDefault:         p.IsDefault,
			LastCheckedAt:     strPtr(lastChecked),
			DefaultForProfile: defaultProfilesForEndpoint(p),
		}
		if ps.ProviderType == "" {
			ps.ProviderType = "endpoint"
		}
		if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
			s := p.CooldownState.Until.UTC().Format(time.RFC3339)
			ps.CooldownUntil = &s
		}
		ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
		ps.RecentWorkerCount = recentWorkerCount(entries, p.Name, agent.MatchProvider, now)
		ps.Quota = quotaFromProviderInfo(p)
		ps.Sparkline = buildSparkline(entries, p.Name, agent.MatchProvider, now)
		results = append(results, ps)
	}
	return results
}

func providerRowsWithUsage(rows []*ProviderStatus, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
	out := cloneProviderRows(rows)
	for _, row := range out {
		row.Usage = buildUsage(entries, row.Name, agent.MatchProvider, now)
		row.RecentWorkerCount = recentWorkerCount(entries, row.Name, agent.MatchProvider, now)
		row.Sparkline = buildSparkline(entries, row.Name, agent.MatchProvider, now)
	}
	return out
}

// buildSparkline returns a 24-element slice of hourly token totals for the
// last 24 hours (oldest-first). Returns nil when fewer than 6 of the 24
// hourly buckets have non-zero token counts — the UI uses that floor to
// suppress noisy single-spike sparklines (FEAT-014 AC 2: "Sparkline renders
// when ≥6 hourly buckets of usage are available").
func buildSparkline(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) []int {
	if len(entries) == 0 {
		return nil
	}
	buckets := agent.BucketUsage(entries, name, kind, now, 1, time.Hour)
	totals := make([]int, len(buckets))
	nonEmpty := 0
	for i, b := range buckets {
		totals[i] = b.Tokens
		if b.Tokens > 0 {
			nonEmpty++
		}
	}
	if nonEmpty < 6 {
		return nil
	}
	return totals
}

func cloneProviderRows(rows []*ProviderStatus) []*ProviderStatus {
	if len(rows) == 0 {
		return nil
	}
	out := make([]*ProviderStatus, 0, len(rows))
	for _, row := range rows {
		if row == nil {
			continue
		}
		clone := *row
		if row.DefaultForProfile != nil {
			clone.DefaultForProfile = append([]string(nil), row.DefaultForProfile...)
		}
		if row.Sparkline != nil {
			clone.Sparkline = append([]int(nil), row.Sparkline...)
		}
		out = append(out, &clone)
	}
	return out
}

// sessionIndexEntries reads the project's session index for all available
// shards. Errors are swallowed — a missing index is a normal "no data" state.
func (r *queryResolver) sessionIndexEntries(ctx context.Context) []agent.SessionIndexEntry {
	logDir := agent.SessionLogDirForWorkDir(r.workingDir(ctx))
	if logDir == "" {
		return nil
	}
	entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
	if err != nil {
		return nil
	}
	return entries
}

func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
	counts := agent.AggregateUsageCounts(entries, name, kind, now)
	// FEAT-014 no-fabrication: when the session index has no rows attributable
	// to this name, return nil so the UI renders "not reported" instead of
	// fabricated "0 / 0" counts.
	if counts.TokensLastHour == 0 && counts.TokensLast24h == 0 &&
		counts.RequestsLastHour == 0 && counts.RequestsLast24h == 0 {
		return nil
	}
	u := &ProviderUsage{}
	v := counts.TokensLastHour
	u.TokensUsedLastHour = &v
	v2 := counts.TokensLast24h
	u.TokensUsedLast24h = &v2
	v3 := counts.RequestsLastHour
	u.RequestsLastHour = &v3
	v4 := counts.RequestsLast24h
	u.RequestsLast24h = &v4
	return u
}

func recentWorkerCount(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) int {
	return agent.AggregateUsageCounts(entries, name, kind, now).RequestsLast24h
}

// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
// Returns nil when no token-level ceiling is published.
func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
	if p.Quota == nil {
		return nil
	}
	return quotaFromState(p.Quota)
}

// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
// When a rate-limit signal has been captured for this harness (via
// RecordHarnessRateLimit — typically on the server's harness-dispatch path
// after parsing response headers with agent.ParseRateLimitHeaders), that
// signal takes precedence because it carries absolute token ceilings. The
// upstream HarnessInfo.Quota only exposes percent-used windows without an
// absolute ceiling. Returns nil when nothing usable is published.
func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
	if sig, ok := LookupHarnessRateLimit(info.Name); ok {
		if q := QuotaFromRateLimitSignal(sig); q != nil {
			return q
		}
	}
	if info.Quota == nil {
		return nil
	}
	return quotaFromState(info.Quota)
}

// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
// used), so we surface the window length and reset time only. Ceiling and
// remaining stay unknown unless a harness-specific rate-limit-header path
// populates them via QuotaFromRateLimitSignal.
func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
	if state == nil || len(state.Windows) == 0 {
		return nil
	}
	var windowSeconds int
	var resetAt string
	for _, w := range state.Windows {
		if strings.EqualFold(w.LimitID, "extra") {
			continue
		}
		if windowSeconds == 0 && w.WindowMinutes > 0 {
			windowSeconds = w.WindowMinutes * 60
		}
		if resetAt == "" {
			if w.ResetsAt != "" {
				resetAt = w.ResetsAt
			} else if w.ResetsAtUnix > 0 {
				resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
			}
		}
		if windowSeconds > 0 && resetAt != "" {
			break
		}
	}
	if windowSeconds == 0 && resetAt == "" {
		return nil
	}
	q := &ProviderQuota{}
	if windowSeconds > 0 {
		v := windowSeconds
		q.CeilingWindowSeconds = &v
	}
	if resetAt != "" {
		v := resetAt
		q.ResetAt = &v
	}
	return q
}

// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
// sites where the server captures harness response headers.
func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
	if !sig.HasAny() {
		return nil
	}
	q := &ProviderQuota{}
	if sig.CeilingTokens >= 0 {
		v := sig.CeilingTokens
		q.CeilingTokens = &v
	}
	if sig.CeilingWindowSeconds >= 0 {
		v := sig.CeilingWindowSeconds
		q.CeilingWindowSeconds = &v
	}
	if sig.Remaining >= 0 {
		v := sig.Remaining
		q.Remaining = &v
	}
	if !sig.ResetAt.IsZero() {
		v := sig.ResetAt.UTC().Format(time.RFC3339)
		q.ResetAt = &v
	}
	return q
}

// defaultProfilesForEndpoint returns the profile names where this endpoint is
// a default candidate. Current service surface exposes only a single
// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
// shape supports multi-profile expansion without breaking callers.
func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
	if p.IsDefault {
		return []string{"default"}
	}
	return []string{}
}

func providerReachable(p agentlib.ProviderInfo) bool {
	return strings.EqualFold(strings.TrimSpace(p.Status), "connected")
}

func providerDetail(p agentlib.ProviderInfo) string {
	if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
		return p.LastError.Detail
	}
	for _, ep := range p.EndpointStatus {
		if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
			return ep.LastError.Detail
		}
		if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
			return ep.Status
		}
	}
	if strings.TrimSpace(p.Status) != "" {
		if strings.EqualFold(p.Status, "unknown") {
			return "not checked yet"
		}
		return p.Status
	}
	return "not reported"
}

func harnessTypeLabel(info agentlib.HarnessInfo) string {
	if info.Type != "" {
		return info.Type
	}
	return "subprocess"
}

func harnessStatusLine(info agentlib.HarnessInfo) string {
	if info.Available {
		return "available"
	}
	if info.Error != "" {
		return "unavailable: " + info.Error
	}
	return "unavailable"
}

func harnessDetail(info agentlib.HarnessInfo) string {
	if info.LastError != nil && strings.TrimSpace(info.LastError.Detail) != "" {
		return info.LastError.Detail
	}
	if strings.TrimSpace(info.Error) != "" {
		return info.Error
	}
	if info.Available && strings.TrimSpace(info.Path) != "" {
		return info.Path
	}
	if info.Available {
		return "available"
	}
	return "binary not found"
}

func harnessModelCount(_ agentlib.HarnessInfo) int {
	// Harness-reported model counts flow through a separate model-discovery
	// path; leave 0 until that surface is exposed to avoid fabricating a
	// number from capability flags.
	return 0
