229	
230		// Translate upstream quota.Status (ok|stale|unavailable|unauthenticated|unknown)
231		// into the existing ddx vocabulary.
232		state := "unknown"
233		switch info.Quota.Status {
234		case "ok":
235			state = "ok"
236		case "stale":
237			state = "ok" // stale-but-present data still counts as headroom.
238		case "unavailable", "unauthenticated":
239			state = "unknown"
